"use client";

export interface OrganicCurvesProps {
  className?: string;
  lineColor?: string;
  backgroundColor?: string;
  dotColor?: string;
  animated?: boolean;
}

export function OrganicCurves({
  className,
  lineColor = "#d4d4d4",
  backgroundColor = "#0a0a0a",
  dotColor = "#f0f0f0",
  animated = true,
}: OrganicCurvesProps) {
  return (
    <div
      className={className ?? "fixed inset-0 pointer-events-none z-0"}
      style={{
        background: backgroundColor,
      }}
    >
      <svg
        viewBox="0 0 1200 800"
        preserveAspectRatio="xMidYMid slice"
        className="w-full h-full"
      >
        <defs>
          <filter id="organic-glow" x="-20%" y="-20%" width="140%" height="140%">
            <feGaussianBlur stdDeviation="4" result="coloredBlur" />
            <feMerge>
              <feMergeNode in="coloredBlur" />
              <feMergeNode in="SourceGraphic" />
            </feMerge>
          </filter>
          <linearGradient id="line-grad" x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" stopColor="#ffffff" stopOpacity="0.9" />
            <stop offset="50%" stopColor={lineColor} stopOpacity="0.7" />
            <stop offset="100%" stopColor="#ffffff" stopOpacity="0.5" />
          </linearGradient>
        </defs>
        <g className={animated ? "organic-curves-group" : undefined} filter="url(#organic-glow)">
          <path
            d="M -100,350 Q 600,150 1300,350"
            fill="none"
            stroke="url(#line-grad)"
            strokeWidth="2"
            className="organic-curve"
          />
          <path
            d="M -100,450 Q 600,650 1300,450"
            fill="none"
            stroke="url(#line-grad)"
            strokeWidth="2"
            className="organic-curve"
          />
          <path
            d="M 200,-100 Q 0,400 200,900"
            fill="none"
            stroke="url(#line-grad)"
            strokeWidth="2"
            className="organic-curve"
          />
          <path
            d="M 1000,-100 Q 1200,400 1000,900"
            fill="none"
            stroke="url(#line-grad)"
            strokeWidth="2"
            className="organic-curve"
          />
          <circle
            cx="600"
            cy="520"
            r="3"
            fill={dotColor}
            className="organic-dot"
          />
        </g>
      </svg>
      {animated && (
        <style>{`
          .organic-curves-group {
            transform-origin: 600px 400px;
            animation: organicRotate 120s linear infinite;
          }
          .organic-curve {
            animation: organicPulse 6s ease-in-out infinite;
          }
          .organic-curve:nth-child(1) { animation-delay: 0s; }
          .organic-curve:nth-child(2) { animation-delay: 1.5s; }
          .organic-curve:nth-child(3) { animation-delay: 3s; }
          .organic-curve:nth-child(4) { animation-delay: 4.5s; }
          .organic-dot {
            animation: organicDotPulse 3s ease-in-out infinite;
            transform-origin: 600px 520px;
          }
          @keyframes organicRotate {
            from { transform: rotate(0deg); }
            to { transform: rotate(360deg); }
          }
          @keyframes organicPulse {
            0%, 100% { opacity: 0.6; }
            50% { opacity: 1; }
          }
          @keyframes organicDotPulse {
            0%, 100% { opacity: 0.6; transform: scale(1); }
            50% { opacity: 1; transform: scale(1.4); }
          }
          @media (prefers-reduced-motion: reduce) {
            .organic-curves-group,
            .organic-curve,
            .organic-dot {
              animation: none !important;
            }
          }
        `}</style>
      )}
    </div>
  );
}
